+        if (matchesLogsPattern(dataStreamName)) {
             return Settings.builder().put("index.mode", IndexMode.LOGSDB.getName()).build();
         }

@@ -74,21 +72,4 @@ final class LogsdbIndexModeSettingsProvider implements IndexSettingProvider {
